const repo = items[0].json.body?.repository?.name || '';
const watched = ['shanebrain-agents','mega-crew','shanebrain_mcp','pico-nerve-endings','mega-crew-stories'];
if (!watched.includes(repo)) return [];
const pusher = items[0].json.body?.pusher?.name || 'unknown';
const commits = items[0].json.body?.commits || [];
const branch = (items[0].json.body?.ref || '').replace('refs/heads/','');
return [{ json: { repo, pusher, branch, commit_count: commits.length, message: commits[0]?.message || '', url: items[0].json.body?.compare || '' } }];

